    mock_IfxGtm_Tom_Timer_init_callCount++;
    return mock_IfxGtm_Tom_Timer_init_returnValue;
}

void IfxGtm_Tom_Timer_initConfig(IfxGtm_Tom_Timer_Config *config, Ifx_GTM *gtm)
